 val periodic=a("chemistry-periodic-trends","Periodic Trend Explorer","chemistry-periodic-trends",setOf(CLASS_10,CLASS_11),"Compare school-level atomic-radius and electronegativity trends across periods and groups.","Across a period effective nuclear attraction generally increases; down a group added shells generally increase radius.",listOf(c("atomicNumber","Atomic number",1.0,18.0,1.0,11.0,"Z"),c("compareAtomicNumber","Comparison atomic number",1.0,18.0,1.0,17.0,"Z")),listOf(ActivityPreset("period3","Na versus Cl",mapOf("atomicNumber" to 11.0,"compareAtomicNumber" to 17.0)),ActivityPreset("group1","Li versus Na",mapOf("atomicNumber" to 3.0,"compareAtomicNumber" to 11.0))),listOf(DiagramPart("table","periodic grid","first 18 elements by group and period"),DiagramPart("radius","radius indicator","relative trend circle"),DiagramPart("en","electronegativity indicator","relative pull scale")),listOf("Trend scores are qualitative teaching indices, not tabulated measured values.","Noble-gas electronegativity is shown as not defined in this model."),{q->fun props(z:Int):Triple<Int,Int,Double>{val period=if(z<=2)1 else if(z<=10)2 else 3;val group=when(z){1,3,11->1;2,10,18->18;else->if(z<=9)z+8 else z};val radius=period*35.0-group*1.5;return Triple(period,group,radius)};val z=q.getValue("atomicNumber").roundToInt();val z2=q.getValue("compareAtomicNumber").roundToInt();val p=props(z);val p2=props(z2);val en=if(p.second==18)0.0 else p.second.toDouble()/p.first;visual(q+mapOf("period" to p.first.toDouble(),"group" to p.second.toDouble(),"radiusTrend" to p.third,"electronegativityTrend" to en,"comparisonRadiusTrend" to p2.third),mapOf("atomicNumber" to "Z","compareAtomicNumber" to "Z","period" to "","group" to "","radiusTrend" to "relative units","electronegativityTrend" to "relative units","comparisonRadiusTrend" to "relative units"),mapOf("selected" to "Z=$z: period ${p.first}, group ${p.second}","comparison" to if(p.third>p2.third)"selected atom has larger qualitative radius